(defn resolve-api-key
  "Resolve API key from environment for a backend."
  [backend]
  (when-let [env-var (get api-key-env-vars backend)]
    (System/getenv env-var)))

(defn load-config
  "Load config from the first existing search path."
  []
  (let [path (->> config-search-paths
                  (map :path)
                  (map #(clojure.string/replace % "~/" (str (System/getProperty "user.home") "/")))
                  (filter #(.exists (java.io.File. %)))
                  first)]
    (when path
      (merge default-config
             (json/parse-string (slurp path) true)))))

